   108→                fetchRequests,
   109→                (fetchTarget, data, clientResponse) -> {
   110→                    synchronized (Fetcher.this) {
   111→                        handleFetchSuccess(fetchTarget, data, clientResponse);
   112→                    }
   113→                },
   114→                (fetchTarget, data, error) -> {
   115→                    synchronized (Fetcher.this) {
   116→                        handleFetchFailure(fetchTarget, data, error);
   117→                    }
   118→                });
   119→        return fetchRequests.size();
   120→    }
   121→
   122→    protected void maybeCloseFetchSessions(final Timer timer) {
   123→        final List<RequestFuture<ClientResponse>> requestFutures = sendFetchesInternal(
   124→                prepareCloseFetchSessionRequests(),
   125→                this::handleCloseFetchSessionSuccess,
   126→                this::handleCloseFetchSessionFailure
   127→        );
   128→
   129→        // Poll to ensure that request has been written to the socket. Wait until either the timer has expired or until
   130→        // all requests have received a response.
   131→        while (timer.notExpired() && !requestFutures.stream().allMatch(RequestFuture::isDone)) {
   132→            client.poll(timer, null, true);
   133→            timer.update();
   134→        }
   135→
   136→        if (!requestFutures.stream().allMatch(RequestFuture::isDone)) {
   137→            // we ran out of time before completing all futures. It is ok since we don't want to block the shutdown
   138→            // here.
   139→            log.debug("All requests couldn't be sent in the specific timeout period {}ms. " +
   140→                    "This may result in unnecessary fetch sessions at the broker. Consider increasing the timeout passed for " +
   141→                    "KafkaConsumer.close(...)", timer.timeoutMs());
   142→        }
   143→    }
   144→
   145→    public Fetch<K, V> collectFetch() {
   146→        return fetchCollector.collectFetch(fetchBuffer);
   147→    }
   148→
