   202→                public void onFailure(RuntimeException e) {
   203→                    errorHandler.handle(fetchTarget, data, e);
   204→                }
   205→            });
   206→
   207→            requestFutures.add(responseFuture);
   208→        }
   209→
   210→        return requestFutures;
   211→    }
