150→    private Fetch<K, V> fetchRecords(final CompletedFetch nextInLineFetch, int maxRecords) {
   151→        final TopicPartition tp = nextInLineFetch.partition;
   152→
   153→        if (!subscriptions.isAssigned(tp)) {
   154→            // this can happen when a rebalance happened before fetched records are returned to the consumer's poll call
   155→            log.debug("Not returning fetched records for partition {} since it is no longer assigned", tp);
   156→        } else if (!subscriptions.isFetchable(tp)) {
   157→            // this can happen when a partition is paused before fetched records are returned to the consumer's
   158→            // poll call or if the offset is being reset.
   159→            // It can also happen under the Consumer rebalance protocol, when the consumer changes its subscription.
   160→            // Until the consumer receives an updated assignment from the coordinator, it can hold assigned partitions
   161→            // that are not in the subscription anymore, so we make them not fetchable.
   162→            log.debug("Not returning fetched records for assigned partition {} since it is no longer fetchable", tp);
   163→        } else {
   164→            SubscriptionState.FetchPosition position = subscriptions.position(tp);
   165→
   166→            if (position == null)
   167→                throw new IllegalStateException("Missing position for fetchable partition " + tp);
   168→
   169→            if (nextInLineFetch.nextFetchOffset() == position.offset) {
   170→                List<ConsumerRecord<K, V>> partRecords = nextInLineFetch.fetchRecords(fetchConfig,
   171→                        deserializers,
   172→                        maxRecords);
   173→
   174→                log.trace("Returning {} fetched records at offset {} for assigned partition {}",
   175→                        partRecords.size(), position, tp);
   176→
   177→                boolean positionAdvanced = false;
   178→
   179→                if (nextInLineFetch.nextFetchOffset() > position.offset) {
   180→                    SubscriptionState.FetchPosition nextPosition = new SubscriptionState.FetchPosition(
   181→                            nextInLineFetch.nextFetchOffset(),
   182→                            nextInLineFetch.lastEpoch(),
   183→                            position.currentLeader);
   184→                    log.trace("Updating fetch position from {} to {} for partition {} and returning {} records from `poll()`",
   185→                            position, nextPosition, tp, partRecords.size());
   186→                    subscriptions.position(tp, nextPosition);
   187→                    positionAdvanced = true;
   188→                }
   189→
   190→                Long partitionLag = subscriptions.partitionLag(tp, fetchConfig.isolationLevel);
   191→                if (partitionLag != null)
   192→                    metricsManager.recordPartitionLag(tp, partitionLag);
   193→
   194→                Long lead = subscriptions.partitionLead(tp);
   195→                if (lead != null) {
   196→                    metricsManager.recordPartitionLead(tp, lead);
   197→                }
