   153→    private void maybeEnsureValid(FetchConfig fetchConfig, RecordBatch batch) {
   154→        if (fetchConfig.checkCrcs && batch.magic() >= RecordBatch.MAGIC_VALUE_V2) {
   155→            try {
   156→                batch.ensureValid();
   157→            } catch (CorruptRecordException e) {
   158→                throw new KafkaException("Record batch for partition " + partition + " at offset " +
   159→                        batch.baseOffset() + " is invalid, cause: " + e.getMessage());
