   182→    private Record nextFetchedRecord(FetchConfig fetchConfig) {
   183→        while (true) {
   184→            if (records == null || !records.hasNext()) {
   185→                maybeCloseRecordStream();
   186→
   187→                if (!batches.hasNext()) {
   188→                    // Message format v2 preserves the last offset in a batch even if the last record is removed
   189→                    // through compaction. By using the next offset computed from the last offset in the batch,
   190→                    // we ensure that the offset of the next fetch will point to the next batch, which avoids
   191→                    // unnecessary re-fetching of the same batch (in the worst case, the consumer could get stuck
   192→                    // fetching the same batch repeatedly).
   193→                    if (currentBatch != null)
   194→                        nextFetchOffset = currentBatch.nextOffset();
   195→                    drain();
   196→                    return null;
   197→                }
   198→
   199→                currentBatch = batches.next();
   200→                lastEpoch = maybeLeaderEpoch(currentBatch.partitionLeaderEpoch());
   201→                maybeEnsureValid(fetchConfig, currentBatch);
   202→
   203→                if (fetchConfig.isolationLevel == IsolationLevel.READ_COMMITTED && currentBatch.hasProducerId()) {
   204→                    // remove from the aborted transaction queue all aborted transactions which have begun
   205→                    // before the current batch's last offset and add the associated producerIds to the
   206→                    // aborted producer set
   207→                    consumeAbortedTransactionsUpTo(currentBatch.lastOffset());
   208→
   209→                    long producerId = currentBatch.producerId();
   210→                    if (containsAbortMarker(currentBatch)) {
   211→                        abortedProducerIds.remove(producerId);
   212→                    } else if (isBatchAborted(currentBatch)) {
   213→                        log.debug("Skipping aborted record batch from partition {} with producerId {} and " +
   214→                                        "offsets {} to {}",
   215→                                partition, producerId, currentBatch.baseOffset(), currentBatch.lastOffset());
   216→                        nextFetchOffset = currentBatch.nextOffset();
   217→                        continue;
   218→                    }
   219→                }
   220→
   221→                records = currentBatch.streamingIterator(decompressionBufferSupplier);
   222→            } else {
   223→                Record record = records.next();
   224→                // skip any records out of range
   225→                if (record.offset() >= nextFetchOffset) {
   226→                    // we only do validation when the message should not be skipped.
   227→                    maybeEnsureValid(fetchConfig, record);
