   304→    /**
   305→     * Parse the record entry, deserializing the key / value fields if necessary
   306→     */
   307→    <K, V> ConsumerRecord<K, V> parseRecord(Deserializers<K, V> deserializers,
   308→                                            TopicPartition partition,
   309→                                            Optional<Integer> leaderEpoch,
   310→                                            TimestampType timestampType,
   311→                                            Record record) {
   312→        ByteBuffer keyBytes = record.key();
   313→        ByteBuffer valueBytes = record.value();
   314→        Headers headers = new RecordHeaders(record.headers());
   315→        K key;
   316→        V value;
   317→        try {
   318→            key = keyBytes == null ? null : deserializers.keyDeserializer().deserialize(partition.topic(), headers, keyBytes);
   319→        } catch (RuntimeException e) {
   320→            log.error("Key Deserializers with error: {}", deserializers);
   321→            throw newRecordDeserializationException(DeserializationExceptionOrigin.KEY, partition, timestampType, record, e, headers);
   322→        }
   323→        try {
   324→            value = valueBytes == null ? null : deserializers.valueDeserializer().deserialize(partition.topic(), headers, valueBytes);
   325→        } catch (RuntimeException e) {
   326→            log.error("Value Deserializers with error: {}", deserializers);
   327→            throw newRecordDeserializationException(DeserializationExceptionOrigin.VALUE, partition, timestampType, record, e, headers);
   328→        }
   329→        return new ConsumerRecord<>(partition.topic(), partition.partition(), record.offset(),
   330→                record.timestamp(), timestampType,
   331→                keyBytes == null ? ConsumerRecord.NULL_SIZE : keyBytes.remaining(),
   332→                valueBytes == null ? ConsumerRecord.NULL_SIZE : valueBytes.remaining(),
   333→                key, value, headers, leaderEpoch);
   334→    }
   335→
   336→    private static RecordDeserializationException newRecordDeserializationException(DeserializationExceptionOrigin origin,
   337→                                                                                    TopicPartition partition,
   338→                                                                                    TimestampType timestampType,
   339→                                                                                    Record record,
   340→                                                                                    RuntimeException e,
   341→                                                                                    Headers headers) {
   342→        return new RecordDeserializationException(origin, partition, record.offset(), record.timestamp(), timestampType, record.key(), record.value(), headers,
   343→                "Error deserializing " + origin.name() + " for partition " + partition + " at offset " + record.offset()
   344→                        + ". If needed, please seek past the record to continue consumption.", e);
   345→    }
