   347→    private Optional<Integer> maybeLeaderEpoch(int leaderEpoch) {
   348→        return leaderEpoch == RecordBatch.NO_PARTITION_LEADER_EPOCH ? Optional.empty() : Optional.of(leaderEpoch);
   349→    }
