   351→    private void consumeAbortedTransactionsUpTo(long offset) {
   352→        if (abortedTransactions == null)
   353→            return;
   354→
   355→        while (!abortedTransactions.isEmpty() && abortedTransactions.peek().firstOffset() <= offset) {
   356→            FetchResponseData.AbortedTransaction abortedTransaction = abortedTransactions.poll();
   357→            abortedProducerIds.add(abortedTransaction.producerId());
   358→        }
   359→    }
