    55→    private final IdempotentCloser idempotentCloser = new IdempotentCloser();
    56→
    57→    private final AtomicBoolean wokenup = new AtomicBoolean(false);
    58→
    59→    private CompletedFetch nextInLineFetch;
    60→
    61→    public FetchBuffer(final LogContext logContext) {
    62→        this.log = logContext.logger(FetchBuffer.class);
    63→        this.completedFetches = new ConcurrentLinkedQueue<>();
    64→        this.lock = new ReentrantLock();
    65→        this.notEmptyCondition = lock.newCondition();
    66→    }
    67→
    68→    /**
    69→     * Returns {@code true} if there are no completed fetches pending to return to the user.
    70→     *
    71→     * @return {@code true} if the buffer is empty, {@code false} otherwise
    72→     */
    73→    boolean isEmpty() {
    74→        try {
    75→            lock.lock();
    76→            return completedFetches.isEmpty();
    77→        } finally {
    78→            lock.unlock();
    79→        }
    80→    }
    81→
    82→    /**
    83→     * Return whether we have any completed fetches pending return to the user. This method is thread-safe. Has
    84→     * visibility for testing.
    85→     *
    86→     * @return {@code true} if there are completed fetches that match the {@link Predicate}, {@code false} otherwise
    87→     */
    88→    boolean hasCompletedFetches(Predicate<CompletedFetch> predicate) {
    89→        try {
    90→            lock.lock();
    91→            return completedFetches.stream().anyMatch(predicate);
    92→        } finally {
    93→            lock.unlock();
    94→        }
    95→    }
    96→
    97→    void add(CompletedFetch completedFetch) {
    98→        try {
    99→            lock.lock();
   100→            completedFetches.add(completedFetch);
   101→            notEmptyCondition.signalAll();
   102→        } finally {
   103→            lock.unlock();
   104→        }
   105→    }
   106→
   107→    void addAll(Collection<CompletedFetch> completedFetches) {
   108→        if (completedFetches == null || completedFetches.isEmpty())
   109→            return;
   110→
   111→        try {
   112→            lock.lock();
   113→            this.completedFetches.addAll(completedFetches);
   114→            notEmptyCondition.signalAll();
   115→        } finally {
   116→            lock.unlock();
   117→        }
   118→    }
   119→
   120→    CompletedFetch nextInLineFetch() {
   121→        try {
   122→            lock.lock();
   123→            return nextInLineFetch;
   124→        } finally {
   125→            lock.unlock();
   126→        }
   127→    }
   128→
   129→    void setNextInLineFetch(CompletedFetch nextInLineFetch) {
   130→        try {
   131→            lock.lock();
   132→            this.nextInLineFetch = nextInLineFetch;
   133→        } finally {
   134→            lock.unlock();
   135→        }
   136→    }
   137→
   138→    CompletedFetch peek() {
   139→        try {
   140→            lock.lock();
   141→            return completedFetches.peek();
   142→        } finally {
   143→            lock.unlock();
   144→        }
   145→    }
   146→
   147→    CompletedFetch poll() {
   148→        try {
   149→            lock.lock();
   150→            return completedFetches.poll();
   151→        } finally {
   152→            lock.unlock();
   153→        }
   154→    }
   155→
   156→    /**
   157→     * Allows the caller to await presence of data in the buffer. The method will block, returning only
   158→     * under one of the following conditions:
   159→     *
   160→     * <ol>
   161→     *     <li>The buffer was already non-empty on entry</li>
   162→     *     <li>The buffer was populated during the wait</li>
   163→     *     <li>The remaining time on the {@link Timer timer} elapsed</li>
   164→     *     <li>The thread was interrupted</li>
   165→     * </ol>
   166→     *
   167→     * @param timer Timer that provides time to wait
   168→     */
   169→    void awaitNotEmpty(Timer timer) {
   170→        try {
   171→            lock.lock();
   172→
   173→            while (isEmpty() && !wokenup.compareAndSet(true, false)) {
   174→                // Update the timer before we head into the loop in case it took a while to get the lock.
   175→                timer.update();
   176→
   177→                if (timer.isExpired()) {
   178→                    // If the thread was interrupted before we start waiting, it still counts as
   179→                    // interrupted from the point of view of the KafkaConsumer.poll(Duration) contract.
   180→                    // We only need to check this when we are not going to wait because waiting
   181→                    // already checks whether the thread is interrupted.
   182→                    if (Thread.interrupted())
   183→                        throw new InterruptException("Interrupted waiting for results from fetching records");
   184→
   185→                    break;
   186→                }
   187→
   188→                if (!notEmptyCondition.await(timer.remainingMs(), TimeUnit.MILLISECONDS)) {
   189→                    break;
   190→                }
   191→            }
   192→        } catch (InterruptedException e) {
   193→            throw new InterruptException("Interrupted waiting for results from fetching records", e);
   194→        } finally {
   195→            lock.unlock();
   196→            timer.update();
   197→        }
   198→    }
   199→
   200→    void wakeup() {
   201→        wokenup.set(true);
   202→        try {
   203→            lock.lock();
   204→            notEmptyCondition.signalAll();
   205→        } finally {
   206→            lock.unlock();
   207→        }
   208→    }
   209→
   210→    /**
   211→     * Updates the buffer to retain only the fetch data that corresponds to the given partitions. Any previously
   212→     * {@link CompletedFetch fetched data} is removed if its partition is not in the given set of partitions.
   213→     *
   214→     * @param partitions {@link Set} of {@link TopicPartition}s for which any buffered data should be kept
   215→     */
   216→    void retainAll(final Set<TopicPartition> partitions) {
   217→        try {
   218→            lock.lock();
   219→
   220→            completedFetches.removeIf(cf -> maybeDrain(partitions, cf));
   221→
   222→            if (maybeDrain(partitions, nextInLineFetch))
   223→                nextInLineFetch = null;
   224→        } finally {
   225→            lock.unlock();
   226→        }
   227→    }
   228→
   229→    /**
   230→     * Drains (i.e. <em>removes</em>) the contents of the given {@link CompletedFetch} as its data should not
   231→     * be returned to the user.
   232→     */
   233→    private boolean maybeDrain(final Set<TopicPartition> partitions, final CompletedFetch completedFetch) {
   234→        if (completedFetch != null && !partitions.contains(completedFetch.partition)) {
   235→            log.debug("Removing {} from buffered fetch data as it is not in the set of partitions to retain ({})", completedFetch.partition, partitions);
   236→            completedFetch.drain();
   237→            return true;
   238→        } else {
   239→            return false;
   240→        }
   241→    }
   242→
   243→    /**
   244→     * Return the set of {@link TopicPartition partitions} for which we have data in the buffer.
   245→     *
   246→     * @return {@link TopicPartition Partition} set
   247→     */
   248→    Set<TopicPartition> bufferedPartitions() {
   249→        try {
   250→            lock.lock();
   251→
   252→            final Set<TopicPartition> partitions = new HashSet<>();
   253→
   254→            if (nextInLineFetch != null && !nextInLineFetch.isConsumed()) {
   255→                partitions.add(nextInLineFetch.partition);
   256→            }
   257→
   258→            completedFetches.forEach(cf -> partitions.add(cf.partition));
   259→            return partitions;
   260→        } finally {
   261→            lock.unlock();
   262→        }
   263→    }
   264→
   265→    @Override
   266→    public void close() {
   267→        try {
   268→            lock.lock();
   269→
   270→            idempotentCloser.close(
   271→                    () -> retainAll(Collections.emptySet()),
   272→                    () -> log.warn("The fetch buffer was already closed")
   273→            );
   274→        } finally {
   275→            lock.unlock();
   276→        }
   277→    }
   278→}
